-- ============================================================
-- MIGRATION: Theory content for all 22 networking topics
-- Creates topic_content table and seeds comprehensive content
-- Safe to run multiple times
-- ============================================================

CREATE TABLE IF NOT EXISTS topic_content (
    id              UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    topic_id        UUID NOT NULL REFERENCES topics(id) ON DELETE CASCADE,
    osi_layer       VARCHAR(32),
    rfc_references  TEXT[],
    theory_md       TEXT NOT NULL,
    practical_md    TEXT NOT NULL,
    diagram_type    VARCHAR(32) DEFAULT 'topology',
    diagram_data    JSONB DEFAULT '{}',
    key_commands    JSONB DEFAULT '[]',
    common_mistakes JSONB DEFAULT '[]',
    created_at      TIMESTAMPTZ DEFAULT NOW(),
    UNIQUE(topic_id)
);

CREATE INDEX IF NOT EXISTS idx_topic_content_topic ON topic_content(topic_id);

-- ============================================================
-- 1. VLANs
-- ============================================================
INSERT INTO topic_content (topic_id, osi_layer, rfc_references, theory_md, practical_md, diagram_type, diagram_data, key_commands, common_mistakes)
SELECT t.id, 'Layer 2 — Data Link', ARRAY['IEEE 802.1Q'],
-- THEORY
E'## What Are VLANs?\n\nA **Virtual LAN (VLAN)** is a logical partition of a Layer 2 network. VLANs divide a single physical switch into multiple **isolated broadcast domains**, so devices in different VLANs cannot communicate directly — even if they share the same switch.\n\n## Why VLANs Exist\n\nWithout VLANs, every device on a switch receives every broadcast frame. In a 500-device campus, this means:\n- **Broadcast storms** consume bandwidth\n- **Security** is nonexistent — any device can sniff all traffic\n- **Performance** degrades as the network grows\n\nVLANs solve all three: each VLAN is its own broadcast domain.\n\n## How VLANs Work\n\n### Access Ports\nAn **access port** belongs to exactly one VLAN. The switch strips the VLAN tag from outgoing frames and adds it to incoming frames. End devices (PCs, printers) never see the VLAN tag.\n\n### Trunk Ports\nA **trunk port** carries traffic for multiple VLANs simultaneously using **802.1Q tagging**. Each Ethernet frame gets a 4-byte tag inserted between the source MAC and EtherType fields:\n\n```\n| Dest MAC | Src MAC | 802.1Q Tag (4B) | EtherType | Payload | FCS |\n                     |TPID|PCP|DEI|VID|\n```\n\n- **TPID**: 0x8100 (identifies 802.1Q)\n- **VID**: 12-bit VLAN ID (1–4094)\n- **PCP**: 3-bit priority (for QoS)\n\n### Native VLAN\nThe **native VLAN** is sent untagged on trunk ports. Both sides must agree on the native VLAN — mismatches cause connectivity issues and security vulnerabilities (VLAN hopping).\n\n### VLAN Database\nVLANs are stored locally on each switch. **VTP (VLAN Trunking Protocol)** can synchronize VLAN databases across switches, but many networks disable it to prevent accidental VLAN deletions.\n\n## Inter-VLAN Routing\n\nDevices in different VLANs need a **Layer 3 device** (router or L3 switch) to communicate:\n- **Router-on-a-stick**: A single router interface with sub-interfaces, one per VLAN\n- **SVI (Switch Virtual Interface)**: L3 switches create virtual interfaces per VLAN\n\n## VLAN Ranges\n\n| Range | Use |\n|-------|-----|\n| 1 | Default VLAN (cannot be deleted) |\n| 2–1001 | Normal range (stored in vlan.dat) |\n| 1002–1005 | Legacy (FDDI/Token Ring) |\n| 1006–4094 | Extended range (requires VTP transparent mode) |',

-- PRACTICAL
E'## When to Use VLANs\n\n- **Department segmentation**: Engineering, Sales, HR on separate VLANs\n- **Guest isolation**: Visitors get internet-only VLAN\n- **Voice VLANs**: Separate VLAN for IP phones (QoS priority)\n- **IoT/OT separation**: Keep cameras, sensors off the corporate VLAN\n\n## Essential IOS Commands\n\n```\n! Create a VLAN\nSwitch(config)# vlan 10\nSwitch(config-vlan)# name Engineering\n\n! Assign an access port\nSwitch(config)# interface GigabitEthernet0/1\nSwitch(config-if)# switchport mode access\nSwitch(config-if)# switchport access vlan 10\nSwitch(config-if)# no shutdown\n\n! Configure a trunk port\nSwitch(config)# interface GigabitEthernet0/24\nSwitch(config-if)# switchport trunk encapsulation dot1q\nSwitch(config-if)# switchport mode trunk\nSwitch(config-if)# switchport trunk allowed vlan 10,20,30\n\n! Verify\nSwitch# show vlan brief\nSwitch# show interfaces trunk\nSwitch# show interfaces switchport\n```\n\n## Troubleshooting Checklist\n\n1. Does the VLAN exist on **both** switches? (`show vlan brief`)\n2. Is the trunk link actually trunking? (`show interfaces trunk`)\n3. Is the VLAN **allowed** on the trunk? (`switchport trunk allowed vlan`)\n4. Do both trunk ends agree on **native VLAN**?\n5. Is the port in the right mode? (`show interfaces switchport`)\n\n## Design Best Practices\n\n- Keep VLAN scope to a single distribution layer (avoid stretched VLANs)\n- Use VLAN 1 for nothing — change the native VLAN to an unused ID\n- Document your VLAN numbering scheme (e.g., 10x = floor 1, 20x = floor 2)\n- Prune trunk links to carry only necessary VLANs',

'frame-format',
'{"nodes":[{"id":"pc1","label":"PC1","vlan":10},{"id":"pc2","label":"PC2","vlan":20},{"id":"sw1","label":"SW1"},{"id":"sw2","label":"SW2"},{"id":"pc3","label":"PC3","vlan":10}],"edges":[{"from":"pc1","to":"sw1","label":"access VLAN 10"},{"from":"pc2","to":"sw1","label":"access VLAN 20"},{"from":"sw1","to":"sw2","label":"trunk 802.1Q"},{"from":"pc3","to":"sw2","label":"access VLAN 10"}]}',
'["vlan {id}", "name {name}", "switchport mode access", "switchport access vlan {id}", "switchport mode trunk", "switchport trunk encapsulation dot1q", "switchport trunk allowed vlan {list}", "show vlan brief", "show interfaces trunk"]',
'["Forgetting to create the VLAN on the remote switch", "Native VLAN mismatch between trunk endpoints", "Not allowing the VLAN on the trunk (default allows all, but pruning can block)", "Leaving ports in VLAN 1 (security risk)", "Using VTP server mode and accidentally deleting VLANs network-wide"]'
FROM topics t WHERE t.slug = 'vlans' AND NOT EXISTS (SELECT 1 FROM topic_content tc WHERE tc.topic_id = t.id);

-- ============================================================
-- 2. STP
-- ============================================================
INSERT INTO topic_content (topic_id, osi_layer, rfc_references, theory_md, practical_md, diagram_type, diagram_data, key_commands, common_mistakes)
SELECT t.id, 'Layer 2 — Data Link', ARRAY['IEEE 802.1D', 'IEEE 802.1w (RSTP)'],
E'## What Is Spanning Tree Protocol?\n\n**STP** prevents Layer 2 loops in networks with redundant links. Without STP, frames loop endlessly, broadcast storms overwhelm the network, and MAC address tables become unstable.\n\n## The Problem STP Solves\n\nWhen two switches are connected by multiple paths, a broadcast frame sent by any host gets forwarded out every port (except the one it arrived on). With redundant links, this creates an infinite loop:\n\n1. SW1 sends broadcast → SW2 via link A\n2. SW2 forwards → SW1 via link B\n3. SW1 forwards → SW2 via link A again\n4. **Infinite loop** — frames multiply exponentially\n\n## How STP Works\n\n### Step 1: Root Bridge Election\nAll switches exchange **BPDUs (Bridge Protocol Data Units)**. The switch with the **lowest Bridge ID** becomes the root bridge.\n\n**Bridge ID** = Priority (4 bits) + System ID Extension (12 bits) + MAC Address\n\nDefault priority is **32768**. To force a switch as root, lower its priority.\n\n### Step 2: Port Role Assignment\n- **Root Port**: Best path toward the root bridge (one per non-root switch)\n- **Designated Port**: Best port on each segment toward the root (forwards traffic)\n- **Blocking Port**: Redundant port — does NOT forward traffic\n\n### Step 3: Port States\n\n| State | Duration | Forwards? | Learns MACs? |\n|-------|----------|-----------|-------------|\n| Blocking | — | No | No |\n| Listening | 15 sec | No | No |\n| Learning | 15 sec | No | Yes |\n| Forwarding | — | Yes | Yes |\n| Disabled | — | No | No |\n\nTotal convergence: ~30–50 seconds (802.1D). **RSTP (802.1w)** converges in <1 second.\n\n### RSTP Port Roles\n- **Alternate Port**: Backup path to root (replaces blocking)\n- **Backup Port**: Redundant path on the same segment\n\n## STP Variants\n\n| Variant | Standard | Convergence | Per-VLAN? |\n|---------|----------|-------------|----------|\n| STP | 802.1D | 30-50 sec | No |\n| RSTP | 802.1w | <1 sec | No |\n| PVST+ | Cisco | 30-50 sec | Yes |\n| Rapid-PVST+ | Cisco | <1 sec | Yes |\n| MST | 802.1s | <1 sec | Grouped |',

E'## When STP Matters\n\n- Any network with **redundant uplinks** between switches\n- Access layer to distribution layer connections\n- Data center leaf-spine (though most modern DC fabrics avoid STP entirely)\n\n## Essential Commands\n\n```\n! Set root bridge for a VLAN\nSwitch(config)# spanning-tree vlan 10 priority 4096\n! Or use the macro:\nSwitch(config)# spanning-tree vlan 10 root primary\n\n! Enable PortFast on access ports\nSwitch(config-if)# spanning-tree portfast\n\n! Enable BPDU Guard\nSwitch(config-if)# spanning-tree bpduguard enable\n\n! Global PortFast default\nSwitch(config)# spanning-tree portfast default\n\n! Switch to Rapid-PVST+\nSwitch(config)# spanning-tree mode rapid-pvst\n\n! Verify\nSwitch# show spanning-tree\nSwitch# show spanning-tree vlan 10\nSwitch# show spanning-tree interface Gi0/1\n```\n\n## Design Best Practices\n\n- **Always** designate a root bridge — never leave it to chance\n- Use **Rapid-PVST+** or MST — classic STP is too slow\n- Enable **PortFast** on all access ports (PCs, servers)\n- Enable **BPDU Guard** on PortFast ports to protect against rogue switches\n- Set **Root Guard** on designated ports to prevent unauthorized root bridges\n- Consider **Loop Guard** on root/alternate ports\n\n## Troubleshooting\n\n1. **Unexpected root bridge?** Check `show spanning-tree` — lowest priority wins\n2. **Port stuck in blocking?** Check for BPDU issues or topology changes\n3. **Errdisabled port?** Likely BPDU Guard triggered — check for unauthorized switch\n4. **Slow convergence?** Switch to Rapid-PVST+',

'state-machine',
'{"states":["Blocking","Listening","Learning","Forwarding","Disabled"],"transitions":[{"from":"Blocking","to":"Listening","label":"Selected as RP/DP"},{"from":"Listening","to":"Learning","label":"15 sec"},{"from":"Learning","to":"Forwarding","label":"15 sec"},{"from":"Forwarding","to":"Blocking","label":"Topology change"}]}',
'["spanning-tree vlan {id} priority {val}", "spanning-tree portfast", "spanning-tree bpduguard enable", "spanning-tree mode rapid-pvst", "show spanning-tree", "spanning-tree vlan {id} root primary"]',
'["Not setting a root bridge — random election causes suboptimal paths", "Forgetting PortFast on access ports — 30-second delay for hosts", "Missing BPDU Guard — rogue switch can become root", "Priority math: must be a multiple of 4096", "Mixing STP and RSTP modes across switches"]'
FROM topics t WHERE t.slug = 'stp' AND NOT EXISTS (SELECT 1 FROM topic_content tc WHERE tc.topic_id = t.id);

-- ============================================================
-- 3. OSPF
-- ============================================================
INSERT INTO topic_content (topic_id, osi_layer, rfc_references, theory_md, practical_md, diagram_type, diagram_data, key_commands, common_mistakes)
SELECT t.id, 'Layer 3 — Network', ARRAY['RFC 2328 (OSPFv2)', 'RFC 5340 (OSPFv3)'],
E'## What Is OSPF?\n\n**Open Shortest Path First (OSPF)** is a link-state interior gateway protocol (IGP). It builds a complete topological map of the network, then uses **Dijkstra''s algorithm** to calculate the shortest path tree from each router to every destination.\n\n## Why OSPF Over RIP?\n\n| Feature | RIP | OSPF |\n|---------|-----|------|\n| Algorithm | Distance-vector (Bellman-Ford) | Link-state (Dijkstra) |\n| Metric | Hop count (max 15) | Cost (bandwidth-based) |\n| Convergence | Slow (30-sec updates) | Fast (triggered updates) |\n| Scalability | Small networks | Enterprise-scale |\n| VLSM/CIDR | RIPv2 only | Full support |\n\n## OSPF Concepts\n\n### Areas\nOSPF uses **areas** to create hierarchy and reduce LSA flooding:\n- **Area 0 (Backbone)**: All areas must connect to area 0\n- **Stub Areas**: Block external LSAs to reduce LSDB size\n- **NSSA**: Allow limited external routes into stub areas\n\n### LSA Types\n\n| Type | Name | Scope | Purpose |\n|------|------|-------|---------|\n| 1 | Router LSA | Area | Each router''s links |\n| 2 | Network LSA | Area | Multi-access network DR |\n| 3 | Summary LSA | Inter-area | Routes between areas |\n| 4 | ASBR Summary | Inter-area | Path to ASBR |\n| 5 | External LSA | Domain-wide | Routes from other protocols |\n\n### Neighbor States\n\n**Down → Init → 2-Way → ExStart → Exchange → Loading → Full**\n\n- **2-Way**: DR/BDR election happens here\n- **Full**: LSDBs are synchronized — adjacency is complete\n\n### DR/BDR Election\nOn multi-access networks (Ethernet), OSPF elects:\n- **DR (Designated Router)**: Reduces LSA flooding — all routers form adjacency with DR\n- **BDR (Backup DR)**: Takes over if DR fails\n\nElection criteria: highest **priority** (default 1), then highest **router ID**.\n\n### Cost Calculation\n\n```\nCost = Reference Bandwidth / Interface Bandwidth\nDefault reference: 100 Mbps\n\nGigabitEthernet: 100/1000 = 0.1 → rounded to 1\nFastEthernet:    100/100  = 1\nSerial:          100/1.544 = 64\n```',

E'## When to Use OSPF\n\n- **Enterprise campus**: Single-area for small sites, multi-area for large\n- **Data center underlay**: OSPF or IS-IS for spine-leaf fabrics\n- **WAN**: OSPF over tunnels, DMVPN, or MPLS VPNs\n\n## Essential Commands\n\n```\n! Enable OSPF\nRouter(config)# router ospf 1\nRouter(config-router)# router-id 1.1.1.1\nRouter(config-router)# network 10.0.1.0 0.0.0.255 area 0\nRouter(config-router)# network 10.0.2.0 0.0.0.255 area 0\n\n! Set interface cost\nRouter(config-if)# ip ospf cost 10\n\n! Change reference bandwidth\nRouter(config-router)# auto-cost reference-bandwidth 10000\n\n! Passive interface (don''t send hellos)\nRouter(config-router)# passive-interface GigabitEthernet0/2\n\n! Verify\nRouter# show ip ospf neighbor\nRouter# show ip ospf database\nRouter# show ip ospf interface brief\nRouter# show ip route ospf\n```\n\n## Design Best Practices\n\n- Keep **Area 0** as the backbone — all other areas connect to it\n- Use **stub areas** to reduce routing table size at branch sites\n- Set **router-id** explicitly — don''t rely on interface IP selection\n- Use **passive-interface default** then enable OSPF only where needed\n- Adjust **reference bandwidth** to 10G or 100G to differentiate modern links\n- Set **hello/dead timers** consistently across all neighbors\n\n## Troubleshooting\n\n1. **Neighbors stuck in INIT?** Check hello/dead timer mismatch, area mismatch, or ACLs blocking OSPF (protocol 89)\n2. **Stuck in EXSTART?** MTU mismatch — both sides must agree\n3. **Missing routes?** Check area configuration and network statements\n4. **Suboptimal path?** Verify costs with `show ip ospf interface`',

'area-hierarchy',
'{"areas":[{"id":0,"label":"Area 0 (Backbone)","routers":["R1","R2","ABR1"]},{"id":1,"label":"Area 1","routers":["ABR1","R3","R4"]},{"id":2,"label":"Area 2 (Stub)","routers":["ABR2","R5"]}]}',
'["router ospf {pid}", "network {ip} {wildcard} area {id}", "show ip ospf neighbor", "show ip ospf database", "router-id {ip}", "passive-interface {if}", "ip ospf cost {val}"]',
'["Mismatched hello/dead timers between neighbors", "Forgetting that wildcard masks are inverted subnet masks", "MTU mismatch preventing Full state", "Not all areas connecting to Area 0", "Leaving reference bandwidth at 100 Mbps (all GigE links show cost 1)"]'
FROM topics t WHERE t.slug = 'ospf' AND NOT EXISTS (SELECT 1 FROM topic_content tc WHERE tc.topic_id = t.id);

-- ============================================================
-- 4. LACP
-- ============================================================
INSERT INTO topic_content (topic_id, osi_layer, rfc_references, theory_md, practical_md, diagram_type, diagram_data, key_commands, common_mistakes)
SELECT t.id, 'Layer 2 — Data Link', ARRAY['IEEE 802.3ad', 'IEEE 802.1AX'],
E'## What Is LACP?\n\n**Link Aggregation Control Protocol (LACP)** bundles multiple physical Ethernet links into a single logical **port-channel** (EtherChannel on Cisco). This provides:\n\n- **Increased bandwidth**: 2× GigE = 2 Gbps logical link\n- **Redundancy**: If one link fails, traffic continues on the remaining links\n- **Load balancing**: Traffic is distributed across member links\n\n## How LACP Works\n\nLACP peers exchange **LACPDUs** (LACP Data Units) every 30 seconds (slow) or 1 second (fast) to:\n1. Discover which ports should be bundled\n2. Negotiate channel formation\n3. Detect link failures\n\n### Modes\n\n| Mode | Behavior |\n|------|----------|\n| **Active** | Initiates LACP negotiation |\n| **Passive** | Responds to LACP but doesn''t initiate |\n\nAt least one side must be **active**. Both sides active works fine.\n\n### PAgP (Cisco proprietary alternative)\n\n| Mode | Behavior |\n|------|----------|\n| **Desirable** | Initiates PAgP |\n| **Auto** | Responds only |\n\n## Load Balancing\n\nThe switch hashes traffic across member links using configurable criteria:\n- **src-mac**: Source MAC address\n- **dst-mac**: Destination MAC\n- **src-dst-mac**: Both MACs (most common L2)\n- **src-dst-ip**: Source + destination IP (best for L3)\n\n## Requirements for Bundling\n\nAll member ports must match:\n- Speed and duplex\n- VLAN configuration (access VLAN or trunk settings)\n- STP settings\n- MTU',

E'## When to Use LACP\n\n- **Switch-to-switch uplinks**: Double or triple bandwidth between distribution and access layers\n- **Server NIC teaming**: Bond multiple server NICs to a switch port-channel\n- **Firewall HA**: High-throughput firewall connections\n\n## Essential Commands\n\n```\n! Configure LACP on member interfaces\nSwitch(config)# interface range GigabitEthernet0/1-2\nSwitch(config-if-range)# channel-group 1 mode active\nSwitch(config-if-range)# no shutdown\n\n! Configure the port-channel interface\nSwitch(config)# interface Port-channel1\nSwitch(config-if)# switchport mode trunk\n\n! Set load balancing method\nSwitch(config)# port-channel load-balance src-dst-ip\n\n! Verify\nSwitch# show etherchannel summary\nSwitch# show etherchannel port-channel\nSwitch# show lacp neighbor\nSwitch# show lacp counters\n```\n\n## Troubleshooting\n\n1. **Channel not forming?** Check that speed, duplex, VLAN, and STP match on all member ports\n2. **Suspended ports?** One side may be misconfigured — check `show etherchannel summary` for (s) flags\n3. **Uneven traffic distribution?** Change the load-balance hash algorithm\n4. **Individual (I) state?** Port is configured but not bundled — check LACP mode compatibility',

'bundle',
'{"links":[{"from":"SW1-Gi0/1","to":"SW2-Gi0/1"},{"from":"SW1-Gi0/2","to":"SW2-Gi0/2"}],"channel":"Po1","bandwidth":"2 Gbps"}',
'["channel-group {id} mode active", "channel-group {id} mode passive", "show etherchannel summary", "show lacp neighbor", "port-channel load-balance {method}", "interface Port-channel{id}"]',
'["Mismatched speed/duplex on member ports", "Configuring the port-channel interface before the member ports", "Mixing LACP and PAgP modes", "Not matching trunk/access settings across all members", "Exceeding 8 active members per channel (Cisco limit)"]'
FROM topics t WHERE t.slug = 'lacp' AND NOT EXISTS (SELECT 1 FROM topic_content tc WHERE tc.topic_id = t.id);

