-- 5. DHCP
INSERT INTO topic_content (topic_id, osi_layer, rfc_references, theory_md, practical_md, diagram_type, diagram_data, key_commands, common_mistakes)
SELECT t.id, 'Layer 7 — Application', ARRAY['RFC 2131'],
E'## What Is DHCP?\n\n**Dynamic Host Configuration Protocol** automatically assigns IP addresses, subnet masks, default gateways, and DNS servers to network clients. Without DHCP, every device would need manual IP configuration.\n\n## DORA Process\n\nDHCP uses a 4-step handshake:\n\n1. **Discover**: Client broadcasts "I need an IP" (UDP 67/68)\n2. **Offer**: Server responds with an available IP\n3. **Request**: Client formally requests the offered IP\n4. **Acknowledge**: Server confirms the lease\n\n## Key Concepts\n\n- **Lease Time**: How long the client keeps the IP (default varies, typically 24h)\n- **Scope/Pool**: Range of IPs the server can assign\n- **Exclusions**: IPs reserved for static devices (routers, servers)\n- **DHCP Relay (ip helper-address)**: Forwards broadcasts across subnets to a central DHCP server\n- **Options**: Extra parameters (Option 150 = TFTP for IP phones, Option 43 = WLC IP for lightweight APs)',
E'## Essential Commands\n\n```\n! Create DHCP pool\nRouter(config)# ip dhcp pool OFFICE\nRouter(dhcp-config)# network 10.0.1.0 255.255.255.0\nRouter(dhcp-config)# default-router 10.0.1.1\nRouter(dhcp-config)# dns-server 8.8.8.8 8.8.4.4\nRouter(dhcp-config)# lease 1\n\n! Exclude addresses\nRouter(config)# ip dhcp excluded-address 10.0.1.1 10.0.1.20\n\n! DHCP relay on remote subnet\nRouter(config-if)# ip helper-address 10.0.0.5\n\n! Verify\nRouter# show ip dhcp binding\nRouter# show ip dhcp pool\nRouter# show ip dhcp conflict\n```\n\n## Troubleshooting\n\n1. **No IP assigned?** Check DHCP pool exists and isn''t exhausted\n2. **Wrong gateway?** Verify default-router in the pool\n3. **Remote subnet not working?** Missing ip helper-address on the gateway interface',
'dora-sequence', '{}',
'["ip dhcp pool {name}", "network {ip} {mask}", "default-router {ip}", "dns-server {ip}", "ip dhcp excluded-address {start} {end}", "ip helper-address {ip}", "show ip dhcp binding"]',
'["Forgetting to exclude the router gateway IP from the pool", "Missing ip helper-address for remote subnets", "Pool network not matching the interface subnet", "DHCP snooping blocking legitimate DHCP on access switches"]'
FROM topics t WHERE t.slug = 'dhcp' AND NOT EXISTS (SELECT 1 FROM topic_content tc WHERE tc.topic_id = t.id);

-- 6. DNS
INSERT INTO topic_content (topic_id, osi_layer, rfc_references, theory_md, practical_md, diagram_type, diagram_data, key_commands, common_mistakes)
SELECT t.id, 'Layer 7 — Application', ARRAY['RFC 1034', 'RFC 1035'],
E'## What Is DNS?\n\n**Domain Name System** translates human-readable hostnames (www.example.com) into IP addresses (93.184.216.34). DNS is hierarchical and distributed.\n\n## DNS Hierarchy\n\n```\n. (root)\n├── .com\n│   ├── example.com\n│   └── google.com\n├── .org\n└── .net\n```\n\n## Record Types\n\n| Type | Purpose | Example |\n|------|---------|--------|\n| A | IPv4 address | www → 10.0.1.5 |\n| AAAA | IPv6 address | www → 2001:db8::1 |\n| CNAME | Alias | mail → server1 |\n| MX | Mail server | @ → mail.example.com |\n| PTR | Reverse lookup | 10.0.1.5 → www |\n| NS | Nameserver | @ → ns1.example.com |\n| SOA | Zone authority | Serial, refresh, retry |\n\n## Resolution Process\n\n1. Client checks **local cache**\n2. Queries configured **DNS server** (recursive resolver)\n3. Resolver queries **root servers** → TLD servers → **authoritative server**\n4. Answer cached at each level per TTL',
E'## Router DNS Commands\n\n```\n! Enable DNS lookup\nRouter(config)# ip domain-lookup\n\n! Set DNS server\nRouter(config)# ip name-server 8.8.8.8\n\n! Set domain name\nRouter(config)# ip domain-name lab.local\n\n! Static host entry\nRouter(config)# ip host server1 10.0.1.100\n\n! Verify\nRouter# show hosts\n```\n\n## Troubleshooting\n\n- `nslookup` or `dig` to test resolution\n- Check if DNS server is reachable (`ping`)\n- Verify `ip name-server` is configured\n- Check for DNS traffic filtering (UDP/TCP port 53)',
'hierarchy', '{}',
'["ip domain-lookup", "ip name-server {ip}", "ip domain-name {name}", "ip host {name} {ip}", "show hosts"]',
'["Forgetting ip domain-lookup", "DNS server unreachable due to missing route", "IOS resolving mistyped commands as hostnames (annoying delay)"]'
FROM topics t WHERE t.slug = 'dns' AND NOT EXISTS (SELECT 1 FROM topic_content tc WHERE tc.topic_id = t.id);

-- 7. BGP
INSERT INTO topic_content (topic_id, osi_layer, rfc_references, theory_md, practical_md, diagram_type, diagram_data, key_commands, common_mistakes)
SELECT t.id, 'Layer 3 — Network', ARRAY['RFC 4271'],
E'## What Is BGP?\n\n**Border Gateway Protocol** is the routing protocol of the internet. BGP is a **path-vector** protocol that exchanges routing information between **autonomous systems (ASes)**. Every ISP, cloud provider, and large enterprise uses BGP.\n\n## eBGP vs iBGP\n\n| Feature | eBGP | iBGP |\n|---------|------|------|\n| Between | Different ASes | Same AS |\n| TTL | 1 (neighbors must be adjacent) | 255 |\n| Next-hop | Changes | Preserved |\n| AS-path | Prepends local AS | No change |\n| Full mesh | No | Required (or use route reflectors) |\n\n## Path Selection (Decision Process)\n\nBGP selects the best path using these criteria **in order**:\n\n1. Highest **Weight** (Cisco-only, local)\n2. Highest **Local Preference** (within AS)\n3. **Locally originated** route preferred\n4. Shortest **AS-Path**\n5. Lowest **Origin** (IGP < EGP < incomplete)\n6. Lowest **MED** (Multi-Exit Discriminator)\n7. **eBGP** over iBGP\n8. Lowest **IGP metric** to next-hop\n9. Oldest route\n10. Lowest **Router ID**\n\n## BGP Message Types\n\n- **OPEN**: Establish session (AS number, router ID, capabilities)\n- **UPDATE**: Advertise/withdraw routes\n- **KEEPALIVE**: Maintain session (every 60 sec)\n- **NOTIFICATION**: Error — session teardown',
E'## Essential Commands\n\n```\n! Start BGP\nRouter(config)# router bgp 65001\nRouter(config-router)# bgp router-id 1.1.1.1\n\n! eBGP neighbor\nRouter(config-router)# neighbor 10.0.0.2 remote-as 65000\n\n! iBGP neighbor\nRouter(config-router)# neighbor 10.1.1.2 remote-as 65001\nRouter(config-router)# neighbor 10.1.1.2 update-source Loopback0\n\n! Advertise prefix\nRouter(config-router)# network 192.168.1.0 mask 255.255.255.0\n\n! Route map for path manipulation\nRouter(config)# route-map SET-LP permit 10\nRouter(config-route-map)# set local-preference 200\n\n! Verify\nRouter# show ip bgp\nRouter# show ip bgp summary\nRouter# show ip bgp neighbors\n```\n\n## Troubleshooting\n\n1. **Session stuck in Active?** Check reachability, AS number, and ACLs\n2. **Route not in table?** Verify the prefix exists in the RIB (BGP network command requires exact match)\n3. **Suboptimal path?** Check local-pref, AS-path, and weight',
'as-topology', '{}',
'["router bgp {asn}", "neighbor {ip} remote-as {asn}", "network {prefix} mask {mask}", "show ip bgp", "show ip bgp summary", "show ip bgp neighbors"]',
'["BGP network command requires an exact match in the routing table", "iBGP requires full mesh or route reflectors", "Forgetting update-source for iBGP over loopbacks", "eBGP peers must be directly connected (or use ebgp-multihop)"]'
FROM topics t WHERE t.slug = 'bgp' AND NOT EXISTS (SELECT 1 FROM topic_content tc WHERE tc.topic_id = t.id);

-- 8. MPLS
INSERT INTO topic_content (topic_id, osi_layer, rfc_references, theory_md, practical_md, diagram_type, diagram_data, key_commands, common_mistakes)
SELECT t.id, 'Layer 2.5', ARRAY['RFC 3031', 'RFC 3032'],
E'## What Is MPLS?\n\n**Multiprotocol Label Switching** forwards packets based on short **labels** instead of long IP addresses. Labels are inserted between the L2 and L3 headers — sometimes called "Layer 2.5".\n\n## Why MPLS?\n\n- **Speed**: Label lookup is simpler than longest-prefix IP lookup (historically significant, less so today)\n- **Traffic Engineering**: Path traffic along specific routes\n- **VPN Services**: L3VPN (RFC 4364) and L2VPN for customers\n- **QoS**: EXP bits in the label for priority marking\n\n## MPLS Label Format (4 bytes)\n\n```\n| Label (20 bits) | EXP (3) | S (1) | TTL (8) |\n```\n\n- **Label**: 0–1,048,575 (0–15 reserved)\n- **EXP**: QoS/Traffic class\n- **S**: Bottom-of-stack (1 = last label)\n- **TTL**: Same as IP TTL\n\n## Key Operations\n\n| Operation | Where | Action |\n|-----------|-------|--------|\n| **Push** | Ingress PE | Add label to packet |\n| **Swap** | Core P | Replace label |\n| **Pop** | Egress PE | Remove label |\n| **PHP** | Penultimate hop | Pop label before egress (optimization) |',
E'## Essential Commands\n\n```\n! Enable MPLS on an interface\nRouter(config-if)# mpls ip\n\n! Verify labels\nRouter# show mpls forwarding-table\nRouter# show mpls ldp neighbor\nRouter# show mpls ldp bindings\nRouter# show mpls interfaces\n```\n\n## Troubleshooting\n\n- **No label for prefix?** Check LDP sessions and IGP reachability\n- **Packet drops at PE?** Verify VRF configuration\n- **PHP not working?** Check implicit-null label assignment',
'label-path', '{}',
'["mpls ip", "show mpls forwarding-table", "show mpls ldp neighbor", "show mpls ldp bindings"]',
'["Forgetting to enable MPLS on all core-facing interfaces", "LDP router-id mismatch", "IGP not converged before MPLS labels assigned"]'
FROM topics t WHERE t.slug = 'mpls' AND NOT EXISTS (SELECT 1 FROM topic_content tc WHERE tc.topic_id = t.id);

-- 9. Network Tunneling
INSERT INTO topic_content (topic_id, osi_layer, rfc_references, theory_md, practical_md, diagram_type, diagram_data, key_commands, common_mistakes)
SELECT t.id, 'Layer 3 — Network', ARRAY['RFC 2784 (GRE)', 'RFC 4301 (IPsec)'],
E'## What Is Network Tunneling?\n\nTunneling **encapsulates** one protocol inside another, creating a virtual point-to-point link across an intermediate network. The original packet becomes the payload of a new outer packet.\n\n## Common Tunnel Types\n\n| Protocol | Encrypts? | Multicast? | Overhead | Use Case |\n|----------|-----------|------------|----------|---------|\n| GRE | No | Yes | 24 bytes | Routing over internet |\n| IPsec | Yes | No (ESP) | 50-70 bytes | Secure site-to-site |\n| GRE+IPsec | Yes | Yes | 74+ bytes | Secure + multicast |\n| VXLAN | No | Yes | 50 bytes | Data center overlay |\n| L2TP | Optional | No | Variable | Remote access VPN |\n\n## Encapsulation\n\n```\nOriginal:  [IP Header] [Payload]\nTunneled:  [New IP Header] [GRE/ESP Header] [Original IP Header] [Payload]\n```\n\nThe **outer IP header** has the tunnel source/destination. The **inner IP header** is the original packet, preserved intact.',
E'## Essential Commands\n\n```\n! GRE tunnel\nRouter(config)# interface Tunnel0\nRouter(config-if)# ip address 10.255.0.1 255.255.255.252\nRouter(config-if)# tunnel source GigabitEthernet0/0\nRouter(config-if)# tunnel destination 203.0.113.2\nRouter(config-if)# tunnel mode gre ip\n\n! Verify\nRouter# show interfaces tunnel 0\nRouter# show ip route\n```\n\n## Key Considerations\n\n- **MTU**: Tunneling adds overhead — reduce MTU or enable fragmentation\n- **Recursive routing**: Don''t route tunnel destination through the tunnel itself\n- **Keepalives**: GRE supports keepalives to detect remote endpoint failure',
'encapsulation', '{}',
'["interface Tunnel{id}", "tunnel source {if}", "tunnel destination {ip}", "tunnel mode gre ip", "show interfaces tunnel {id}"]',
'["Recursive routing: tunnel destination learned via the tunnel itself", "MTU issues causing fragmentation and black holes", "Forgetting to route the tunnel destination via a non-tunnel path"]'
FROM topics t WHERE t.slug = 'tunneling' AND NOT EXISTS (SELECT 1 FROM topic_content tc WHERE tc.topic_id = t.id);

-- 10. GRE
INSERT INTO topic_content (topic_id, osi_layer, rfc_references, theory_md, practical_md, diagram_type, diagram_data, key_commands, common_mistakes)
SELECT t.id, 'Layer 3 — Network', ARRAY['RFC 2784', 'RFC 2890'],
E'## What Is GRE?\n\n**Generic Routing Encapsulation** is a simple tunneling protocol that can encapsulate virtually any network-layer protocol. GRE tunnels are commonly used to:\n\n- Run **OSPF, EIGRP, or multicast** over the internet (IPsec alone can''t carry multicast)\n- Connect non-contiguous private networks\n- Create overlay networks\n\n## GRE Header\n\n```\n| C | R | K | S | s | Recur | Flags | Version | Protocol Type |\n| Checksum (optional)  | Offset (optional)   |\n| Key (optional)       |\n| Sequence (optional)  |\n```\n\nMinimum GRE overhead: **4 bytes** (plus 20 bytes for the new IP header = 24 total).\n\n## GRE vs IPsec\n\n| Feature | GRE | IPsec | GRE over IPsec |\n|---------|-----|-------|---------------|\n| Encryption | No | Yes | Yes |\n| Multicast | Yes | No | Yes |\n| Overhead | 24B | 50-70B | 74+B |\n| Routing protocols | Yes | No | Yes |',
E'## Essential Commands\n\n```\n! Create GRE tunnel\nRouter(config)# interface Tunnel0\nRouter(config-if)# ip address 10.255.0.1 255.255.255.252\nRouter(config-if)# tunnel source GigabitEthernet0/0\nRouter(config-if)# tunnel destination 198.51.100.2\nRouter(config-if)# no shutdown\n\n! Run OSPF over GRE\nRouter(config)# router ospf 1\nRouter(config-router)# network 10.255.0.0 0.0.0.3 area 0\n\n! Verify\nRouter# show interfaces tunnel 0\nRouter# ping 10.255.0.2\n```',
'tunnel', '{}',
'["interface Tunnel{id}", "tunnel source {if/ip}", "tunnel destination {ip}", "tunnel mode gre ip", "show interfaces tunnel {id}"]',
'["Forgetting no shutdown on the tunnel interface", "Recursive routing loop", "Not adjusting MTU/MSS for tunnel overhead"]'
FROM topics t WHERE t.slug = 'gre' AND NOT EXISTS (SELECT 1 FROM topic_content tc WHERE tc.topic_id = t.id);

-- 11-22: Remaining topics (shorter format)
-- 11. Autonomous Systems
INSERT INTO topic_content (topic_id, osi_layer, rfc_references, theory_md, practical_md, diagram_type, diagram_data, key_commands, common_mistakes)
SELECT t.id, 'Layer 3 — Network', ARRAY['RFC 1930', 'RFC 6996'],
E'## What Is an Autonomous System?\n\nAn **AS** is a collection of IP networks under a single administrative domain that presents a common routing policy to the internet. Each AS is identified by a unique **ASN (AS Number)**.\n\n## ASN Ranges\n\n| Range | Type |\n|-------|------|\n| 1–64495 | Public (IANA assigned) |\n| 64512–65534 | Private (16-bit) |\n| 4200000000–4294967294 | Private (32-bit) |\n\n## Internet Structure\n\n- **Tier 1**: Global transit providers (peer freely, no upstream)\n- **Tier 2**: Regional ISPs (buy transit from Tier 1, peer with each other)\n- **Tier 3**: Local ISPs (buy transit from Tier 2)\n- **Enterprises**: Single or multi-homed to ISPs\n\n## Peering Types\n\n- **Transit**: Pay upstream for full internet routing table\n- **Peering**: Exchange traffic directly (settlement-free or paid) at IXPs\n- **Customer**: Your downstream pays you for connectivity',
E'## Practical Considerations\n\n- Most enterprises use **private ASNs** with their ISP\n- Multi-homed enterprises need a **public ASN** and **provider-independent IP space**\n- Configure iBGP within your AS, eBGP to peers/providers\n\n## Commands\n\n```\nRouter(config)# router bgp 65001\nRouter(config-router)# neighbor 10.0.0.1 remote-as 65000\nRouter# show ip bgp summary\n```',
'internet-hierarchy', '{}',
'["router bgp {asn}", "show ip bgp summary", "show ip bgp"]',
'["Using public ASN when private would suffice", "Not filtering routes at AS boundaries"]'
FROM topics t WHERE t.slug = 'autonomous-systems' AND NOT EXISTS (SELECT 1 FROM topic_content tc WHERE tc.topic_id = t.id);

-- 12. IPv6
INSERT INTO topic_content (topic_id, osi_layer, rfc_references, theory_md, practical_md, diagram_type, diagram_data, key_commands, common_mistakes)
SELECT t.id, 'Layer 3 — Network', ARRAY['RFC 8200', 'RFC 4861 (NDP)'],
E'## What Is IPv6?\n\n**IPv6** is the successor to IPv4, expanding the address space from 32 bits (4.3 billion addresses) to **128 bits** (340 undecillion addresses). IPv6 also simplifies the header, eliminates NAT for most use cases, and mandates IPsec support.\n\n## Address Format\n\n```\n2001:0DB8:0000:0001:0000:0000:0000:0001\n2001:DB8:0:1::1      (compressed)\nPrefix: 2001:DB8:0:1::/64\n```\n\n## Address Types\n\n| Type | Prefix | Purpose |\n|------|--------|---------|\n| Global Unicast | 2000::/3 | Public routable |\n| Link-Local | FE80::/10 | Same-link only (auto-configured) |\n| Unique Local | FC00::/7 | Private (like RFC 1918) |\n| Multicast | FF00::/8 | One-to-many |\n| Loopback | ::1 | Localhost |\n\n## NDP (Neighbor Discovery Protocol)\n\nReplaces ARP in IPv6:\n- **Router Solicitation/Advertisement**: Discover routers and prefixes\n- **Neighbor Solicitation/Advertisement**: Resolve IPv6 → MAC\n- **SLAAC**: Stateless Address Auto-Configuration using RA prefix + EUI-64',
E'## Essential Commands\n\n```\n! Enable IPv6 routing\nRouter(config)# ipv6 unicast-routing\n\n! Configure address\nRouter(config-if)# ipv6 address 2001:DB8:1::1/64\nRouter(config-if)# ipv6 address FE80::1 link-local\n\n! Enable OSPFv3\nRouter(config)# ipv6 router ospf 1\nRouter(config-if)# ipv6 ospf 1 area 0\n\n! Verify\nRouter# show ipv6 interface brief\nRouter# show ipv6 neighbors\nRouter# show ipv6 route\n```',
'address-format', '{}',
'["ipv6 unicast-routing", "ipv6 address {addr}/{prefix}", "show ipv6 interface brief", "show ipv6 route", "show ipv6 neighbors"]',
'["Forgetting ipv6 unicast-routing globally", "Not understanding link-local scope", "EUI-64 exposing MAC addresses (privacy concern)"]'
FROM topics t WHERE t.slug = 'ipv6' AND NOT EXISTS (SELECT 1 FROM topic_content tc WHERE tc.topic_id = t.id);

-- 13. Remote Access
INSERT INTO topic_content (topic_id, osi_layer, rfc_references, theory_md, practical_md, diagram_type, diagram_data, key_commands, common_mistakes)
SELECT t.id, 'Layer 3–7', ARRAY['RFC 4301 (IPsec)', 'RFC 7296 (IKEv2)'],
E'## Remote Access Technologies\n\n**Remote access** allows users outside the corporate network to securely connect to internal resources. Key technologies:\n\n- **IPsec VPN**: Full tunnel, encrypts all traffic, requires client software\n- **SSL/TLS VPN**: Browser-based or lightweight client, works through firewalls\n- **DMVPN**: Dynamic multipoint VPN for hub-and-spoke WAN\n- **Site-to-Site VPN**: Permanent tunnel between two fixed locations\n\n## IPsec Phases\n\n**Phase 1 (ISAKMP/IKE)**: Negotiate encryption, authenticate peers, establish secure channel\n**Phase 2 (IPsec)**: Negotiate data encryption parameters, create Security Associations (SAs)\n\n## VPN Split Tunneling\n\n- **Full tunnel**: ALL traffic goes through VPN\n- **Split tunnel**: Only corporate traffic through VPN; internet goes direct',
E'## Essential Commands\n\n```\n! ISAKMP policy\nRouter(config)# crypto isakmp policy 10\nRouter(config-isakmp)# encryption aes 256\nRouter(config-isakmp)# hash sha256\nRouter(config-isakmp)# authentication pre-share\n\n! IPsec transform set\nRouter(config)# crypto ipsec transform-set MYSET esp-aes 256 esp-sha256-hmac\n\n! Crypto map\nRouter(config)# crypto map MYMAP 10 ipsec-isakmp\nRouter(config-crypto-map)# set peer 203.0.113.2\nRouter(config-crypto-map)# set transform-set MYSET\nRouter(config-crypto-map)# match address VPN-TRAFFIC\n\n! Verify\nRouter# show crypto isakmp sa\nRouter# show crypto ipsec sa\n```',
'vpn-tunnel', '{}',
'["crypto isakmp policy {id}", "crypto ipsec transform-set {name}", "crypto map {name}", "show crypto isakmp sa", "show crypto ipsec sa"]',
'["Mismatched ISAKMP policies between peers", "ACL for interesting traffic not matching both directions", "NAT translating VPN traffic (need NAT exemption)"]'
FROM topics t WHERE t.slug = 'remote-access' AND NOT EXISTS (SELECT 1 FROM topic_content tc WHERE tc.topic_id = t.id);

-- 14. SSH
INSERT INTO topic_content (topic_id, osi_layer, rfc_references, theory_md, practical_md, diagram_type, diagram_data, key_commands, common_mistakes)
SELECT t.id, 'Layer 7 — Application', ARRAY['RFC 4253'],
E'## What Is SSH?\n\n**Secure Shell** provides encrypted remote management of network devices, replacing insecure **Telnet** (which sends everything in plaintext, including passwords).\n\n## SSH vs Telnet\n\n| Feature | Telnet | SSH |\n|---------|--------|-----|\n| Encryption | None | AES/ChaCha20 |\n| Authentication | Password only | Password, keys, certificates |\n| Port | TCP 23 | TCP 22 |\n| Security | Terrible | Strong |\n\n## SSH Versions\n\n- **SSHv1**: Deprecated, vulnerable to man-in-the-middle attacks\n- **SSHv2**: Current standard, supports key exchange, stronger algorithms\n\n## How SSH Works\n\n1. **Key Exchange**: Diffie-Hellman to establish shared secret\n2. **Server Authentication**: Server presents its RSA/ECDSA key\n3. **User Authentication**: Password or public key\n4. **Encrypted Channel**: All subsequent traffic is encrypted',
E'## Essential Commands\n\n```\n! Prerequisites\nRouter(config)# hostname R1\nRouter(config)# ip domain-name lab.local\n\n! Generate RSA keys\nRouter(config)# crypto key generate rsa modulus 2048\n\n! Create local user\nRouter(config)# username admin privilege 15 secret <STRONG-PASSWORD>\n\n! Configure VTY lines\nRouter(config)# line vty 0 4\nRouter(config-line)# transport input ssh\nRouter(config-line)# login local\nRouter(config-line)# exec-timeout 5 0\n\n! Force SSH version 2\nRouter(config)# ip ssh version 2\n\n! Verify\nRouter# show ip ssh\nRouter# show ssh\n```',
'auth-flow', '{}',
'["crypto key generate rsa modulus 2048", "ip ssh version 2", "transport input ssh", "login local", "show ip ssh"]',
'["Forgetting hostname and domain-name (required for RSA key generation)", "Leaving transport input as telnet ssh (should be ssh only)", "Using RSA key smaller than 2048 bits", "Not setting exec-timeout (sessions stay open forever)"]'
FROM topics t WHERE t.slug = 'ssh' AND NOT EXISTS (SELECT 1 FROM topic_content tc WHERE tc.topic_id = t.id);

-- 15. ACLs
INSERT INTO topic_content (topic_id, osi_layer, rfc_references, theory_md, practical_md, diagram_type, diagram_data, key_commands, common_mistakes)
SELECT t.id, 'Layer 3–4', ARRAY['RFC 3704 (BCP 38)'],
E'## What Are ACLs?\n\n**Access Control Lists** are ordered rules that **permit or deny** traffic based on criteria like source/destination IP, protocol, and port number. ACLs are fundamental to network security and traffic control.\n\n## ACL Types\n\n| Type | Number Range | Matches On |\n|------|-------------|------------|\n| Standard | 1–99, 1300–1999 | Source IP only |\n| Extended | 100–199, 2000–2699 | Source IP, dest IP, protocol, port |\n| Named | Text name | Flexible (standard or extended) |\n\n## Processing Rules\n\n1. ACLs are processed **top-down** — first match wins\n2. There is an **implicit deny any** at the end\n3. ACLs are applied **per-interface, per-direction** (in or out)\n4. One ACL per interface per direction per protocol\n\n## Direction Logic\n\n- **Inbound**: Filter packets arriving ON the interface\n- **Outbound**: Filter packets leaving THROUGH the interface',
E'## Essential Commands\n\n```\n! Named extended ACL\nRouter(config)# ip access-list extended DENY-TELNET\nRouter(config-ext-nacl)# deny tcp any any eq 23\nRouter(config-ext-nacl)# permit ip any any\n\n! Apply to interface\nRouter(config-if)# ip access-group DENY-TELNET in\n\n! Standard ACL\nRouter(config)# access-list 10 permit 10.0.1.0 0.0.0.255\n\n! Verify\nRouter# show access-lists\nRouter# show ip interface (shows applied ACLs)\n```\n\n## Best Practices\n\n- Place **extended ACLs close to the source**\n- Place **standard ACLs close to the destination**\n- Always end with an explicit `permit ip any any` if you want to allow other traffic\n- Use **named ACLs** for easier editing (can insert/delete lines)',
'rule-processing', '{}',
'["ip access-list extended {name}", "permit {proto} {src} {dst} eq {port}", "deny {proto} {src} {dst}", "ip access-group {name} in/out", "show access-lists"]',
'["Forgetting the implicit deny at the end", "Placing extended ACL far from source (inefficient)", "Applying ACL in the wrong direction (in vs out)", "Not including permit ip any any when needed"]'
FROM topics t WHERE t.slug = 'acls' AND NOT EXISTS (SELECT 1 FROM topic_content tc WHERE tc.topic_id = t.id);

-- 16. NAT
INSERT INTO topic_content (topic_id, osi_layer, rfc_references, theory_md, practical_md, diagram_type, diagram_data, key_commands, common_mistakes)
SELECT t.id, 'Layer 3 — Network', ARRAY['RFC 3022'],
E'## What Is NAT?\n\n**Network Address Translation** maps private (RFC 1918) IP addresses to public IP addresses, allowing internal hosts to access the internet. NAT also provides a degree of security by hiding internal addressing.\n\n## NAT Terminology\n\n| Term | Meaning |\n|------|---------|\n| Inside Local | Private IP on the internal network |\n| Inside Global | Public IP representing the internal host |\n| Outside Local | How the external host appears internally |\n| Outside Global | Real public IP of the external host |\n\n## NAT Types\n\n- **Static NAT**: Permanent 1:1 mapping (e.g., web server)\n- **Dynamic NAT**: Pool of public IPs, assigned on demand\n- **PAT (Overload)**: Many-to-one using port numbers',
E'## Essential Commands\n\n```\n! Define inside/outside\nRouter(config-if)# ip nat inside  (on LAN interface)\nRouter(config-if)# ip nat outside (on WAN interface)\n\n! Static NAT\nRouter(config)# ip nat inside source static 10.0.1.100 203.0.113.100\n\n! Dynamic NAT\nRouter(config)# ip nat pool MYPOOL 203.0.113.10 203.0.113.20 netmask 255.255.255.0\nRouter(config)# access-list 1 permit 10.0.1.0 0.0.0.255\nRouter(config)# ip nat inside source list 1 pool MYPOOL\n\n! Verify\nRouter# show ip nat translations\nRouter# show ip nat statistics\nRouter# clear ip nat translation *\n```',
'translation-table', '{}',
'["ip nat inside", "ip nat outside", "ip nat inside source static {local} {global}", "ip nat inside source list {acl} pool {name}", "show ip nat translations"]',
'["Forgetting to mark interfaces as inside/outside", "ACL not matching the correct source network", "NAT pool exhaustion (not enough public IPs)", "Not clearing NAT translations after config changes"]'
FROM topics t WHERE t.slug = 'nat' AND NOT EXISTS (SELECT 1 FROM topic_content tc WHERE tc.topic_id = t.id);

-- 17. PAT
INSERT INTO topic_content (topic_id, osi_layer, rfc_references, theory_md, practical_md, diagram_type, diagram_data, key_commands, common_mistakes)
SELECT t.id, 'Layer 3–4', ARRAY['RFC 3022'],
E'## What Is PAT?\n\n**Port Address Translation** (also called NAT Overload) maps multiple internal IP addresses to a **single public IP** by using unique **source port numbers** to distinguish sessions.\n\n## How PAT Works\n\n```\nInternal:  10.0.1.10:49152 → 8.8.8.8:53\nTranslated: 203.0.113.1:1024 → 8.8.8.8:53\n\nInternal:  10.0.1.11:49153 → 8.8.8.8:53\nTranslated: 203.0.113.1:1025 → 8.8.8.8:53\n```\n\nBoth hosts share 203.0.113.1, distinguished by source ports.\n\n## PAT vs NAT\n\n| Feature | Static/Dynamic NAT | PAT |\n|---------|-------------------|-----|\n| Mapping | 1:1 | Many:1 |\n| Public IPs needed | One per host | One total |\n| Port tracking | No | Yes |\n| Inbound connections | Yes (static) | No (requires port forwarding) |',
E'## Essential Commands\n\n```\n! PAT using interface IP\nRouter(config)# access-list 1 permit 10.0.1.0 0.0.0.255\nRouter(config)# ip nat inside source list 1 interface GigabitEthernet0/1 overload\n\n! Don''t forget inside/outside\nRouter(config-if)# ip nat inside\nRouter(config-if)# ip nat outside\n\n! Verify\nRouter# show ip nat translations\nRouter# show ip nat statistics\n```\n\nThe key difference from dynamic NAT is the **overload** keyword.',
'port-mapping', '{}',
'["ip nat inside source list {acl} interface {if} overload", "show ip nat translations", "show ip nat statistics"]',
'["Forgetting the overload keyword (without it, only one host can translate)", "ACL not matching all internal subnets", "Port exhaustion under very heavy load (65535 port limit per IP)"]'
FROM topics t WHERE t.slug = 'pat' AND NOT EXISTS (SELECT 1 FROM topic_content tc WHERE tc.topic_id = t.id);

-- 18. Wireless APs
INSERT INTO topic_content (topic_id, osi_layer, rfc_references, theory_md, practical_md, diagram_type, diagram_data, key_commands, common_mistakes)
SELECT t.id, 'Layer 1–2', ARRAY['IEEE 802.11'],
E'## Wireless Access Points\n\nA **wireless access point (AP)** is a Layer 2 device that bridges wireless clients to the wired LAN. APs operate in the **2.4 GHz** and **5 GHz** bands (and now 6 GHz with Wi-Fi 6E).\n\n## Key Concepts\n\n- **SSID**: Network name broadcast by the AP\n- **BSSID**: AP''s MAC address for a specific SSID\n- **Channel**: Frequency slice the AP operates on\n- **802.11 Standards**: a/b/g/n/ac/ax (Wi-Fi 4/5/6)\n\n## 2.4 GHz Channels\n\nOnly channels **1, 6, and 11** are non-overlapping. Using any other channel causes **co-channel interference** with neighbors.\n\n## AP Modes\n\n- **Autonomous**: Self-managed, standalone configuration\n- **Lightweight (LWAP)**: Managed by a Wireless LAN Controller (WLC)\n- **FlexConnect**: WLC-managed but can switch traffic locally',
E'## Deployment Tips\n\n- Use **non-overlapping channels** (1/6/11 for 2.4 GHz)\n- Set **transmit power** to minimize overlap between APs\n- Mount APs **ceiling height, facing down**\n- Plan for **20-25 clients per AP** in enterprise environments\n- Use **5 GHz** for high-density areas (more non-overlapping channels)\n\n## Commands (Autonomous AP)\n\n```\nAP(config)# dot11 ssid CorpWiFi\nAP(config-ssid)# authentication open\nAP(config-ssid)# authentication key-management wpa version 2\nAP(config-ssid)# wpa-psk ascii MySecretKey\n```',
'channel-plan', '{}',
'["dot11 ssid {name}", "authentication open", "channel {num}", "power local {level}"]',
'["Using overlapping channels (e.g., 1 and 3)", "Too many APs at high power (increases interference)", "Not separating management and client VLANs", "Placing APs in closets or corners instead of open ceilings"]'
