-- 19. Wireless Controllers
INSERT INTO topic_content (topic_id, osi_layer, rfc_references, theory_md, practical_md, diagram_type, diagram_data, key_commands, common_mistakes)
SELECT t.id, 'Layer 2–3', ARRAY['RFC 5415 (CAPWAP)'],
E'## Wireless LAN Controllers\n\nA **WLC** centrally manages multiple lightweight access points (LWAPs). Instead of configuring each AP individually, you configure the WLC once and it pushes settings to all APs.\n\n## CAPWAP Protocol\n\n**Control And Provisioning of Wireless Access Points** (UDP 5246/5247):\n- **Control channel**: Encrypted management traffic\n- **Data channel**: Client traffic (can be tunneled to WLC or locally switched)\n\n## WLC Functions\n\n- AP discovery and registration\n- WLAN/SSID management\n- Security policy enforcement\n- Roaming coordination\n- RF management (channel, power)\n- Client load balancing',
E'## Deployment Architecture\n\n- **Centralized**: All traffic tunnels through WLC (control + data)\n- **FlexConnect**: Control through WLC, data switched locally at AP\n- **Cloud-managed**: Meraki/Mist — WLC function in the cloud\n\n## Key Concepts\n\n```\n! WLC WLAN creation\nwlan CorpWiFi 1 CorpWiFi\n  security wpa wpa2\n  security wpa akm dot1x\n  no shutdown\n\n! Map WLAN to VLAN\ninterface vlan 10\n```\n\n## AP Join Process\n\n1. AP boots, gets IP via DHCP\n2. AP discovers WLC (DHCP option 43, DNS, broadcast)\n3. CAPWAP tunnel established\n4. AP downloads config and firmware\n5. AP begins broadcasting SSIDs',
'capwap', '{}',
'["wlan {name} {id} {ssid}", "security wpa wpa2", "no shutdown", "show ap summary"]',
'["DHCP Option 43 not configured for AP discovery", "Firmware mismatch between AP and WLC", "Not enough AP licenses on the WLC", "CAPWAP ports blocked by firewall"]'
FROM topics t WHERE t.slug = 'wireless-controller' AND NOT EXISTS (SELECT 1 FROM topic_content tc WHERE tc.topic_id = t.id);

-- 20. Wireless Security
INSERT INTO topic_content (topic_id, osi_layer, rfc_references, theory_md, practical_md, diagram_type, diagram_data, key_commands, common_mistakes)
SELECT t.id, 'Layer 2', ARRAY['IEEE 802.11i', 'IEEE 802.1X'],
E'## Wireless Security\n\n### Evolution of Wi-Fi Security\n\n| Protocol | Year | Encryption | Status |\n|----------|------|-----------|--------|\n| WEP | 1997 | RC4 | **Broken** — cracked in minutes |\n| WPA | 2003 | TKIP | Deprecated |\n| WPA2 | 2004 | AES-CCMP | Current standard |\n| WPA3 | 2018 | AES-GCMP / SAE | Recommended |\n\n### Authentication Modes\n\n- **Personal (PSK)**: Pre-shared key — all users share one password\n- **Enterprise (802.1X)**: Per-user authentication via RADIUS server\n\n### 802.1X Components\n\n- **Supplicant**: Client device\n- **Authenticator**: AP or WLC\n- **Authentication Server**: RADIUS (FreeRADIUS, ISE, NPS)\n\n### Wireless Threats\n\n- **Rogue APs**: Unauthorized APs on the network\n- **Evil Twin**: Fake AP mimicking a legitimate SSID\n- **Deauthentication attacks**: Spoofed deauth frames (mitigated by PMF/802.11w)\n- **KRACK**: Key reinstallation attack on WPA2 (patched)',
E'## Best Practices\n\n1. Use **WPA3-Enterprise** (or WPA2-Enterprise minimum)\n2. Enable **PMF (802.11w)** to protect management frames\n3. Deploy **802.1X with RADIUS** for per-user credentials\n4. Enable **rogue AP detection** on the WLC\n5. Use **strong PSK** if Enterprise isn''t feasible (20+ characters)\n6. Disable **WPS** (Wi-Fi Protected Setup) — vulnerable to brute force\n\n## Commands\n\n```\n! WPA3-Enterprise on WLC\nwlan SecureWiFi 1 SecureWiFi\n  security wpa3\n  security dot1x\n  security pmf required\n\n! RADIUS server\nradius server ISE\n  address ipv4 10.0.1.200 auth-port 1812\n  key MyRADIUSSecret\n```',
'auth-flow', '{}',
'["security wpa3", "security dot1x", "security pmf required", "radius server {name}", "address ipv4 {ip}"]',
'["Still using WPA2-Personal in enterprise environments", "Not enabling PMF (allows deauth attacks)", "Weak PSK (under 12 characters)", "Not deploying rogue AP detection"]'
FROM topics t WHERE t.slug = 'wireless-security' AND NOT EXISTS (SELECT 1 FROM topic_content tc WHERE tc.topic_id = t.id);

-- 21. Wireless Topology
INSERT INTO topic_content (topic_id, osi_layer, rfc_references, theory_md, practical_md, diagram_type, diagram_data, key_commands, common_mistakes)
SELECT t.id, 'Layer 1–2', ARRAY['IEEE 802.11'],
E'## Wireless Network Design\n\nDesigning a wireless network requires balancing **coverage**, **capacity**, and **interference**.\n\n## Site Survey Types\n\n- **Predictive**: Software-based planning using floor plans\n- **Passive**: Walk the site with a survey tool, measuring existing RF\n- **Active**: Connect to APs and measure real throughput\n\n## Design Considerations\n\n- **Coverage area**: Each AP covers roughly 2,500–3,500 sq ft\n- **Client density**: 20-25 clients per AP in typical office\n- **Channel planning**: Non-overlapping channels (1/6/11 for 2.4 GHz)\n- **AP placement**: Ceiling-mounted, avoid metal obstructions\n- **Roaming**: Overlap between APs for seamless handoff\n\n## Deployment Models\n\n- **Autonomous**: Each AP managed individually\n- **Controller-based**: Centralized WLC management\n- **Cloud-managed**: Meraki, Mist — management from the cloud\n- **Mesh**: APs wirelessly backhaul to each other',
E'## Design Rules of Thumb\n\n1. **20% overlap** between adjacent APs for roaming\n2. **Channel plan first** — then adjust power to match\n3. **5 GHz preferred** for high-density (more channels available)\n4. **Separate SSIDs** for corporate, guest, IoT\n5. **Band steering**: Push dual-band clients to 5 GHz\n\n## Channel Planning\n\n```\n2.4 GHz: Channels 1, 6, 11 (non-overlapping)\n5 GHz:   Channels 36-48, 52-64, 100-144, 149-165\n         (UNII-1, UNII-2, UNII-2e, UNII-3)\n6 GHz:   Channels 1-233 (Wi-Fi 6E) — 59 non-overlapping 20 MHz channels\n```',
'site-plan', '{}',
'["channel {num}", "power local {level}", "dot11 ssid {name}"]',
'["All APs on the same channel", "APs at max power causing interference", "Not accounting for wall attenuation", "Skipping a proper site survey"]'
FROM topics t WHERE t.slug = 'wireless-topology' AND NOT EXISTS (SELECT 1 FROM topic_content tc WHERE tc.topic_id = t.id);

-- 22. Firewalls
INSERT INTO topic_content (topic_id, osi_layer, rfc_references, theory_md, practical_md, diagram_type, diagram_data, key_commands, common_mistakes)
SELECT t.id, 'Layer 3–7', ARRAY['RFC 2979'],
E'## What Is a Firewall?\n\nA firewall controls traffic between network segments by enforcing **security policies**. Modern firewalls are **stateful** — they track connection state and allow return traffic automatically.\n\n## Firewall Types\n\n| Type | Inspects | Example |\n|------|----------|--------|\n| Packet filter | IP/port headers | Router ACLs |\n| Stateful | Connection state | Cisco ASA, iptables |\n| Application (NGFW) | L7 content | Palo Alto, Firepower |\n| WAF | HTTP requests | CloudFlare, F5 |\n\n## Zone-Based Firewall (ZBF)\n\nCisco IOS zone-based firewalls group interfaces into **security zones**:\n\n- **INSIDE**: Trusted internal network\n- **OUTSIDE**: Untrusted internet\n- **DMZ**: Semi-trusted servers (web, mail)\n\n**Zone pairs** define allowed traffic directions:\n- INSIDE → OUTSIDE: Allow and inspect\n- OUTSIDE → INSIDE: Deny (except return traffic)\n- INSIDE → DMZ: Allow specific ports\n\n## Stateful Inspection\n\nThe firewall maintains a **state table** tracking every active connection. Return traffic matching an existing session is automatically permitted — no explicit rule needed.',
E'## Essential Commands (IOS ZBF)\n\n```\n! Create zones\nRouter(config)# zone security INSIDE\nRouter(config)# zone security OUTSIDE\n\n! Assign interfaces to zones\nRouter(config-if)# zone-member security INSIDE\nRouter(config-if)# zone-member security OUTSIDE\n\n! Class-map to match traffic\nRouter(config)# class-map type inspect match-any ALLOWED\nRouter(config-cmap)# match protocol http\nRouter(config-cmap)# match protocol https\nRouter(config-cmap)# match protocol dns\n\n! Policy-map to define action\nRouter(config)# policy-map type inspect INSIDE-OUT\nRouter(config-pmap)# class type inspect ALLOWED\nRouter(config-pmap-c)# inspect\n\n! Zone pair\nRouter(config)# zone-pair security IN-OUT source INSIDE destination OUTSIDE\nRouter(config-sec-zone-pair)# service-policy type inspect INSIDE-OUT\n\n! Verify\nRouter# show zone security\nRouter# show zone-pair security\nRouter# show policy-map type inspect\n```',
'zone-diagram', '{}',
'["zone security {name}", "zone-member security {name}", "zone-pair security {name} source {z1} destination {z2}", "class-map type inspect", "policy-map type inspect", "service-policy type inspect"]',
'["Forgetting that traffic between zones is denied by default", "Not creating zone pairs for both directions when needed", "Blocking return traffic by not using inspect", "Assigning an interface to a zone breaks existing connectivity until policies are applied"]'
FROM topics t WHERE t.slug = 'firewalls' AND NOT EXISTS (SELECT 1 FROM topic_content tc WHERE tc.topic_id = t.id);
